// Label.cpp - Custom Label Widget
#include "Label.h"

Label::Label()
{
    mX = 0;
    mY = 0;
    mWidth = 100;
    mHeight = 30;
    mText = "";
    mFont = Font::FONT_DWARVENTODCRAFT12;
    mColor = Color(255, 255, 255);
    mJustify = Justification::LEFT;
}

void Label::Draw(Graphics* g)
{
    if (!mText.empty())
    {
        g->SetFont(mFont);
        g->SetColor(mColor);
        g->DrawString(mText, mX, mY, mWidth, mHeight, mJustify);
    }
}

