// Label.h - Custom Label Widget
#pragma once

#include "Widget.h"
#include "Graphics.h"
#include "Font.h"
#include "Color.h"

class Label : public Widget
{
public:
    Label();
    virtual ~Label() {}

    virtual void Draw(Graphics* g) override;

    // Properties
    int mX;
    int mY;
    int mWidth;
    int mHeight;
    std::string mText;
    Font* mFont;
    Color mColor;
    Justification mJustify;
};
